const { SQSClient, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { DynamoDBClient, PutItemCommand } = require('@aws-sdk/client-dynamodb');

// Set up AWS credentials and region
process.env.AWS_ACCESS_KEY_ID = 'YOUR_ACCESS_KEY';
process.env.AWS_SECRET_ACCESS_KEY = 'YOUR_SECRET_KEY';
process.env.AWS_REGION = 'your-region';

const sqsClient = new SQSClient({ region: process.env.AWS_REGION });
const dynamoDBClient = new DynamoDBClient({ region: process.env.AWS_REGION });

// Set up SQS queue URL and database table name
const QUEUE_URL = 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name';
const DATABASE_TABLE_NAME = 'your-table-name';

async function processMessage(message) {
  try {
    // Validate message content (e.g., check for required fields)
    if (!message || !message.body) {
      console.error('Invalid message');
      return;
    }

    const transactionData = JSON.parse(message.body);
    const transactionId = transactionData.transaction_id;

    // Update database with new transaction data
    const putItemCommand = new PutItemCommand({
      TableName: DATABASE_TABLE_NAME,
      Item: {
        id: { S: transactionId },
        amount: { N: transactionData.amount.toString() },
        status: { S: transactionData.status },
      },
    });

    await dynamoDBClient.send(putItemCommand);
  } catch (error) {
    console.error('Error processing message:', error);
  }
}

async function receiveAndProcessMessages() {
  try {
    const receiveMessageCommand = new GetMessagesCommand({
      QueueUrl: QUEUE_URL,
      MaxNumberOfMessages: 10,
    });

    const response = await sqsClient.send(receiveMessageCommand);

    if (response.Messages) {
      for (const message of response.Messages) {
        await processMessage(message);
        // Delete the message from SQS
        const deleteMessageCommand = new DeleteMessageCommand({
          QueueUrl: QUEUE_URL,
          ReceiptHandle: message.ReceiptHandle,
        });
        await sqsClient.send(deleteMessageCommand);
      }
    } else {
      console.log('No messages in queue');
    }
  } catch (error) {
    console.error('Error receiving and processing messages:', error);
  }
}

// Run the consumer
setInterval(receiveAndProcessMessages, 1000); // Process messages every second